/** SSOT — aligned with `@linm-soft/common-components` `erpListRowEditHintDismiss.ts`. */
export const ERP_LIST_ROW_EDIT_HINT_DISMISS_STORAGE_KEY = 'linm.erp.list-row-edit-hint.understood';

export function isRowEditHintDismissed(storageKey: string): boolean {
  if (typeof window === 'undefined') return false;
  try {
    return window.localStorage.getItem(storageKey) === '1';
  } catch {
    return false;
  }
}

export function setRowEditHintDismissed(storageKey: string): void {
  if (typeof window === 'undefined') return;
  try {
    window.localStorage.setItem(storageKey, '1');
  } catch {
    /* ignore quota / private mode */
  }
}
